     1→// Simplified slice shader without ViewPlaneUbo
     2→// The view plane information is encoded in the frame's u/v vectors
     3→
     4→// --- Frame Uniform Buffer Object (UBO) ---
     5→// Provides view parameters (origin, basis vectors)
     6→struct FrameUbo {
     7→    origin_mm : vec4<f32>,   // World position at NDC (0,0) (homogeneous, w = 1)
     8→    u_mm      : vec4<f32>,   // World vector for NDC [0,1] in X direction
     9→    v_mm      : vec4<f32>,   // World vector for NDC [0,1] in Y direction
    10→    atlas_dim : vec3<u32>,   // Dimensions of the 3D texture atlas
    11→    _padding  : u32,         // Padding to maintain alignment
    12→    target_dim: vec2<u32>,   // Dimensions of the render target
    13→    _padding2 : vec2<u32>,   // Padding to maintain 16-byte alignment
    14→};
    15→
    16→// --- Crosshair UBO ---
    17→struct CrosshairUbo {
    18→    world_position: vec3<f32>,
    19→    show_crosshair: u32,     // 0 = hide, 1 = show
    20→};
    21→
    22→// --- Per-Layer UBO ---
    23→// Matches LayerUboStd140 in Rust (144 bytes, std140-compliant)
    24→struct LayerUBO {
    25→    // --- 16-byte aligned types first ---
    26→    world_to_voxel : mat4x4<f32>,      // offset 0, size 64
    27→    texture_coords : vec4<f32>,        // offset 64, size 16 (u_min, v_min, u_max, v_max)
    28→    
    29→    // --- vec3 + scalar to fill 16 bytes ---
    30→    dim            : vec3<u32>,        // offset 80, size 12
    31→    padSlices      : u32,              // offset 92, size 4 (completes 16-byte block)
    32→    
    33→    // --- 4 scalars to fill 16 bytes ---
    34→    colormap_id    : u32,              // offset 96, size 4
    35→    blend_mode     : u32,              // offset 100, size 4 (0=alpha, 1=add, 2=max, 3=min)
    36→    layer_index    : u32,              // offset 104, size 4
    37→    threshold_mode : u32,              // offset 108, size 4 (0=range, 1=absolute)
    38→    
    39→    // --- 4 scalars to fill 16 bytes ---
    40→    opacity        : f32,              // offset 112, size 4
    41→    intensity_min  : f32,              // offset 116, size 4
    42→    intensity_max  : f32,              // offset 120, size 4
    43→    thresh_low     : f32,              // offset 124, size 4
    44→    
    45→    // --- Final scalar + padding ---
    46→    thresh_high    : f32,              // offset 128, size 4
    47→    isMask         : u32,              // offset 132, size 4
    48→    // Implicit padding to 144 bytes
    49→};
    50→
    51→// --- Bind Group 0: Per-Frame Globals ---
    52→@group(0) @binding(0) var<uniform> frame: FrameUbo;
    53→@group(0) @binding(1) var<uniform> crosshair: CrosshairUbo;
    54→
    55→// --- Bind Group 1: Layer Data ---
    56→@group(1) @binding(0) var<uniform> layerUBOs : array<LayerUBO, 8>; // Max 8 layers
    57→@group(1) @binding(1) var<uniform> activeLayerCount : u32;
    58→
    59→// --- Bind Group 2: Textures & Samplers ---
    60→@group(2) @binding(0) var volumeTexture: texture_3d<f32>;
    61→@group(2) @binding(1) var samplerLinear: sampler;
    62→@group(2) @binding(2) var colormapLutTexture: texture_2d_array<f32>;
    63→@group(2) @binding(3) var cmSampler: sampler;
    64→
    65→// --- Vertex Shader Output ---
    66→struct VsOut {
    67→    @builtin(position) clip_position: vec4<f32>,
    68→    @location(0) world_mm: vec3<f32>,
    69→};
    70→
    71→// --- Vertex Shader ---
    72→@vertex
    73→fn vs_main(@builtin(vertex_index) vid: u32) -> VsOut {
    74→    // Generate full-screen quad vertices in NDC space [0, 1]
    75→    var ndc: vec2<f32>;
    76→    switch (vid) {
    77→        case 0u: { ndc = vec2<f32>(0.0, 0.0); }  // Bottom-left
    78→        case 1u: { ndc = vec2<f32>(1.0, 0.0); }  // Bottom-right
    79→        case 2u: { ndc = vec2<f32>(0.0, 1.0); }  // Top-left
    80→        case 3u: { ndc = vec2<f32>(0.0, 1.0); }  // Top-left
    81→        case 4u: { ndc = vec2<f32>(1.0, 0.0); }  // Bottom-right
    82→        default: { ndc = vec2<f32>(1.0, 1.0); }  // Top-right
    83→    }
    84→    
    85→    // Convert to clip space [-1, 1]
    86→    let clip_pos = ndc * 2.0 - 1.0;
    87→    
    88→    // Calculate world position using frame
    89→    let world_pos = frame.origin_mm + ndc.x * frame.u_mm + ndc.y * frame.v_mm;
    90→    
    91→    var output: VsOut;
    92→    output.clip_position = vec4<f32>(clip_pos, 0.0, 1.0);
    93→    output.world_mm = world_pos.xyz;
    94→    return output;
    95→}
    96→
    97→// --- Fragment Shader Helpers ---
    98→
    99→// Sample a layer at the given world coordinate
   100→fn sampleLayer(layer: LayerUBO, world_mm: vec3<f32>) -> vec4<f32> {
   101→    // Transform world to voxel coordinates
   102→    let voxel_coord_h = layer.world_to_voxel * vec4<f32>(world_mm, 1.0);
   103→    if (voxel_coord_h.w <= 0.0) { return vec4<f32>(0.0); }
   104→    let voxel_coord = voxel_coord_h.xyz / voxel_coord_h.w;
   105→    
   106→    // Check bounds - return a debug color for out-of-bounds
   107→    if (any(voxel_coord < vec3<f32>(0.0)) || any(voxel_coord >= vec3<f32>(layer.dim))) {
   108→        // Return red for out-of-bounds debugging
   109→        // return vec4<f32>(1.0, 0.0, 0.0, 0.5);
   110→        return vec4<f32>(0.0);
   111→    }
   112→    
   113→    // Convert voxel coordinates to texture coordinates
   114→    let atlas_size = vec3<f32>(frame.atlas_dim);
   115→    let normalized_coord = voxel_coord / atlas_size;
   116→    
   117→    // Sample texture
   118→    let raw_value = textureSample(volumeTexture, samplerLinear, normalized_coord).r;
   119→    
   120→    // Handle binary masks
   121→    if (layer.isMask == 1u) {
   122→        // For binary masks, any non-zero value should be visible
   123→        // Since R8Unorm normalizes 0-255 to 0-1, a value of 128 becomes 0.5
   124→        let alpha = select(0.0, layer.opacity, raw_value > 0.1);
   125→        return vec4<f32>(vec3<f32>(1.0), alpha);
   126→    }
   127→    
   128→    // Window/level normalization
   129→    let intensity_delta = max(layer.intensity_max - layer.intensity_min, 1e-9);
   130→    let intensity_norm = clamp((raw_value - layer.intensity_min) / intensity_delta, 0.0, 1.0);
   131→    
   132→    // Apply thresholding
   133→    var alpha = layer.opacity;
   134→    if (layer.threshold_mode == 1u) {
   135→        // Absolute value thresholding
   136→        let abs_value = abs(raw_value);
   137→        if (abs_value < layer.thresh_low || abs_value > layer.thresh_high) {
   138→            alpha = 0.0;
   139→        }
   140→    } else {
   141→        // Range thresholding
   142→        if (raw_value < layer.thresh_low || raw_value > layer.thresh_high) {
   143→            alpha = 0.0;
   144→        }
   145→    }
   146→    
   147→    // Apply colormap
   148→    let lut_coord = vec2<f32>(intensity_norm, 0.5);
   149→    let rgb_color = textureSample(colormapLutTexture, cmSampler, lut_coord, i32(layer.colormap_id)).rgb;
